INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (1, 'Understanding Your Governing Documents', 'What is the "Declaration"?', 'The Declaration (formally titled the “Restated Declaration of Covenants, Easements, Conditions, Restrictions and Assessments for Walden’s Revisited”) is the master legal document that governs the entire community. It establishes the rules for how property can be used, what can and cannot be built, how common areas are managed, how assessments (dues) are collected, and how the community association operates. Think of it as the community’s “constitution.” It was restated and approved on March 9, 2019 by at least 75% of all lot owners and runs with the land — meaning it binds every current and future owner automatically.', 'Declaration, Preamble and Article I', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (2, 'Understanding Your Governing Documents', 'What are the "Bylaws" (Code of Regulations)?', 'The Code of Regulations (also called the Bylaws) is the operational rulebook for Walden’s Revisited Inc., the nonprofit corporation that serves as the homeowners association. While the Declaration sets out what the rules are, the Bylaws explain how the Association runs day-to-day: how meetings are called, how directors are elected, how votes are counted, how officers serve, and how the organization is structured. The Bylaws are attached to the Declaration as Exhibit B.', 'Declaration, Art. II(G); Bylaws, Art. I', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (3, 'Understanding Your Governing Documents', 'What are the "Association Governing Documents"?', 'This is the umbrella term for all documents that govern the community. It includes the Declaration, the Articles of Incorporation filed with the Ohio Secretary of State, the Code of Regulations (Bylaws), any Rules adopted by the Board, all amendments and supplements, applicable building and zoning laws, and any recorded plats.', 'Declaration, Art. II(E)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (4, 'Understanding Your Governing Documents', 'What law governs our community?', 'Walden’s Revisited is a Planned Community organized under Chapter 5312 of the Ohio Revised Code (the “Planned Community Act”).', 'Declaration, Preamble (A); Art. II(V)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (5, 'Membership & Voting', 'Am I automatically a member of the Association?', 'Yes. Every owner of a lot is automatically a member of Walden’s Revisited Inc. Membership is appurtenant to your lot — it transfers automatically when ownership changes and cannot be separately terminated or severed. In the case of a lot subject to a recorded land installment contract, the vendee (buyer) — not the vendor (seller) — holds the membership.', 'Declaration, Art. VII(A); Bylaws, Art. II, §2.01', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (6, 'Membership & Voting', 'How many votes does my lot get?', 'Each lot gets exactly one vote, regardless of how many people own it. If a lot is co-owned, those co-owners share the single vote. A majority of attending co-owners controls the vote; if only one co-owner attends, that person votes for the lot.', 'Bylaws, Art. II, §2.02–2.03', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (7, 'Membership & Voting', 'Can I vote by proxy?', 'Yes. You may appoint a proxy in writing. The proxy instrument must be filed with the Secretary of the meeting before the proxy holder votes. Proxies expire 11 months after execution unless you specify a longer period.', 'Bylaws, Art. II, §2.05', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (8, 'Membership & Voting', 'Can the Association take action without holding a meeting?', 'Yes. Any action that could be taken at a Members’ meeting can instead be taken in writing signed by Members holding at least 75% of the total voting power. Votes may also be conducted by mail, requiring approval from a majority of the total voting power of all Members (or such greater or lesser proportion as the governing documents or law require for the specific action).', 'Bylaws, Art. III, §3.09', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (9, 'Membership & Voting', 'Can my voting rights be suspended?', 'Yes, in two situations: (1) if you are more than 60 days delinquent on any assessment, your voting rights and common area privileges (except basic ingress and egress to your lot) are suspended until paid; or (2) the Board may suspend voting rights after notice and hearing for up to 30 days per infraction for violations of published rules or the Declaration.', 'Declaration, Art. IX(G)(9); Bylaws, Art. IV, §4.10(g)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (10, 'Board of Directors & Governance', 'How many directors are on the Board?', 'Three. The initial Board was set up with staggered terms — one director got a one-year term, another a two-year term, and the third a three-year term — so that one seat comes up for election each year. Directors elected thereafter serve three-year terms.', 'Declaration, Art. VII(B); Bylaws, Art. IV, §4.01', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (11, 'Board of Directors & Governance', 'Who can serve as a director?', 'A director must be an owner, the spouse of an owner, or a principal, member, partner, director, officer, trustee, or employee of an entity that is an owner.', 'Bylaws, Art. IV, §4.01', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (12, 'Board of Directors & Governance', 'How are directors elected?', 'Directors are elected at Members’ meetings. Candidates may be nominated by a Nominating Committee or from the floor. The candidates receiving the greatest percentage of votes cast for their respective positions are elected. The Declaration separately provides that Board members shall be elected with approval of owners holding not less than 75% of the voting power of all owners.', 'Declaration, Art. VII(B); Bylaws, Art. III, §3.08; Art. IV, §4.02', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (13, 'Board of Directors & Governance', 'Can a director be removed?', 'Yes. A director may be removed by the affirmative vote of members holding at least 75% of total voting power, at a special meeting called for that purpose.', 'Bylaws, Art. IV, §4.01', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (14, 'Board of Directors & Governance', 'What happens if a Board seat becomes vacant?', 'The remaining directors appoint a replacement. If they cannot agree within 30 days, a special meeting of members must be held within 60 days to fill the vacancy. The replacement serves the remainder of the departing director’s term.', 'Bylaws, Art. IV, §4.03', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (15, 'Board of Directors & Governance', 'How often does the Board meet?', 'At least once per calendar quarter. The President may call additional meetings. Meetings can be held electronically or by phone as long as all directors can hear or read in real time and participate and respond to every other director.', 'Bylaws, Art. IV, §4.04', 6);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (16, 'Board of Directors & Governance', 'Are directors compensated?', 'No. Directors receive no compensation, but they may be reimbursed for actual expenses incurred in performing their duties if approved by the Board. A director may serve the Association in another capacity (e.g., as a contractor) and receive compensation for that separate role, subject to the governing documents.', 'Bylaws, Art. IV, §4.07', 7);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (17, 'Board of Directors & Governance', 'Can I attend Board meetings?', 'Not automatically. No owner other than a director may attend or participate in Board meetings unless the Board expressly authorizes it.', 'Bylaws, Art. IV, §4.06', 8);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (18, 'Board of Directors & Governance', 'What are the Board''s general powers?', 'The Board manages the business and affairs of the Association. This includes adopting budgets, setting and collecting all types of assessments (including special assessments, with no dollar cap requiring member approval), enforcing the Declaration and rules, maintaining common areas, entering into contracts, hiring professionals (such as attorneys, property managers, or managing agents), borrowing funds, investing excess funds, and performing all acts necessary to carry out the Association’s purposes. However, certain major actions require a vote of the members — such as amending the Declaration (75% of voting power), terminating the Declaration (80% of voting power), or dissolving the Association (unanimous consent).', 'Bylaws, Art. IV, §4.10; Declaration, Art. IX(E); Art. XI(A), (C)', 9);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (19, 'Board of Directors & Governance', 'Can the Board declare a director''s seat vacant?', 'Yes. The Board may declare the office of a director vacant if that director is absent from three consecutive regular Board meetings.', 'Bylaws, Art. IV, §4.10(h)', 10);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (20, 'Member Meetings', 'When is the annual meeting?', 'During the first quarter of each calendar (or fiscal) year, on a date set by the Board, or on such other date within one month thereafter as the Board designates.', 'Bylaws, Art. III, §3.01', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (21, 'Member Meetings', 'How are special meetings called?', 'Under the Bylaws, special meetings may be called by the President or by a majority of the Directors acting with or without a meeting. If a written request to call a special meeting is delivered to the President or Secretary and is refused, the persons making the request may call the meeting themselves by giving proper notice. The Bylaws do not independently grant members the right to call a special meeting; however, Ohio law (ORC §1702.17(A)(3)) may provide an additional right for the lesser of 10% of voting members or 25 voting members to call one, since the Bylaws do not prohibit it.', 'Bylaws, Art. III, §3.02; ORC §1702.17(A)(3)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (22, 'Member Meetings', 'How much notice is required for a meeting?', 'Written notice must be given not more than 60 days and not less than 5 days before the meeting, by personal delivery or mail to each member’s address on file. The notice must state the time, place, and purpose(s) of the meeting. If a meeting is adjourned to another time or place, no further notice is needed if the new time and place are announced at the meeting.', 'Bylaws, Art. III, §3.04', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (23, 'Member Meetings', 'What constitutes a quorum at a member meeting?', 'The Bylaws define a quorum as whatever number of members entitled to vote are present in person or by proxy. However, the Board may set a minimum number of attendees for a quorum to ensure adequate participation. Actions are taken by majority of those present, unless a higher threshold is required elsewhere in the governing documents or by law.', 'Bylaws, Art. III, §3.06', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (24, 'Assessments (Dues & Fees)', 'What types of assessments can the Association levy?', 'Four types: (1) Operating Assessments — regular annual dues for common expenses; (2) Special Assessments — for unanticipated operating deficiencies, capital expenditures not covered by reserves, or other purposes the Board determines appropriate; (3) Individual Lot Assessments — charges specific to one lot (violations, repairs, legal fees, utility charges, additional insurance costs); and (4) Membership Transfer Assessments — a $100 fee due each time a lot with a dwelling is sold to a bona fide purchaser (or a land installment contract is recorded).', 'Declaration, Art. IX(B), (C)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (25, 'Assessments (Dues & Fees)', 'What is the annual Operating Assessment?', 'The initial annual assessment was set at $150 per lot by the Declarant. It increases each subsequent year by at least the same percentage as the National Consumer Price Index increase. The Board sets the exact amount each year by dividing the Association’s projected gross expenses among all lots that have a dwelling constructed and conveyed to a home purchaser.', 'Declaration, Art. IX(D)(1)–(2)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (26, 'Assessments (Dues & Fees)', 'When are assessments due?', 'Operating Assessments are due in full within 10 days of issuance, unless the Board allows payment in monthly, quarterly, or semi-annual installments. If payable in installments, the assessment notice must include the installment due dates and be given at least 10 days before the first installment is due. Special Assessments require at least 30 days’ written notice before they are due.', 'Declaration, Art. IX(D)(2)(iii); Art. IX(E)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (27, 'Assessments (Dues & Fees)', 'What happens if I don''t pay my assessment?', 'Significant consequences follow after 10 days of delinquency: (1) the Board may accelerate the entire remaining balance due immediately, without demand or notice; (2) interest accrues on the entire unpaid balance at up to 12% per year (or the highest rate permitted by law, whichever is less), plus a reasonable administrative late fee; (3) payments you do make are applied first to accrued interest, then to late fees, then to enforcement and collection costs (including attorney fees), and only then to the delinquent principal; (4) the Association may file a certificate of lien against your lot with the Delaware County Recorder; (5) the Association may sue you personally and/or foreclose the lien; and (6) after 60 days, your voting rights and common area privileges (except basic access to your lot) are suspended until paid. You are also jointly and severally personally liable for all collection costs, including reasonable attorney fees, and this personal obligation passes to your successors in title.', 'Declaration, Art. IX(G)(1)–(6), (9)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (28, 'Assessments (Dues & Fees)', 'How long does an assessment lien last?', 'A filed certificate of lien remains valid for five years from the filing date, unless released, satisfied, or discharged earlier by court order.', 'Declaration, Art. IX(G)(5)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (29, 'Assessments (Dues & Fees)', 'Can I be exempt from paying assessments?', 'No. No owner may gain exemption by waiving or foregoing use of common areas or by abandoning a lot. Operating and Special Assessments are fixed at a uniform rate for all lots. The only “Exempt Property” is property owned by governmental entities or by the Association itself, and only if not used as a residence.', 'Declaration, Art. IX(B); Art. II(K)', 6);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (30, 'Assessments (Dues & Fees)', 'Does a lien for unpaid assessments survive a sale or foreclosure?', 'The Association’s assessment lien is subordinate to a duly recorded first mortgage that was recorded before the Association’s lien certificate was filed. A first-mortgage holder who takes possession through foreclosure, deed in lieu, or assignment takes the property free of unpaid assessments that accrued before the sale date (for foreclosure) or the date title vested (for all other cases). However, in an ordinary sale (not a first-mortgage foreclosure), the new owner and the former owner are jointly and severally liable for delinquent assessments — the lien is not wiped out.', 'Declaration, Art. IX(G)(4), (6)', 7);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (31, 'Assessments (Dues & Fees)', 'How do I get proof that my assessments are current (for a sale)?', 'Request an estoppel certificate from the Board in writing. They will issue a signed certificate within a reasonable time, for a reasonable charge, stating whether assessments on your lot have been paid. This certificate is conclusive evidence of payment.', 'Declaration, Art. IX(G)(8)', 8);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (32, 'Use of Your Lot', 'What can I use my lot for?', 'Single-family residential purposes only, plus purposes customarily incidental to a residence. No industry, business, trade, occupation, or profession is permitted without prior written Board approval.', 'Declaration, Art. IV(A), (G)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (33, 'Use of Your Lot', 'What are the minimum house sizes?', 'One-story homes must have at least 1,750 square feet of finished area; two-story homes must have at least 2,250 square feet. These figures exclude attached garages and open porches. No residence more than two stories in height at the front elevation is permitted.', 'Declaration, Art. IV(A)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (34, 'Use of Your Lot', 'Can I build more than one home on my lot?', 'No. Only one residence is permitted per lot, and garages must be attached to the residence. When two or more lots are joined for a single residence, side lot setback lines apply only to the lot lines bordering the adjoining owner.', 'Declaration, Art. IV(A)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (35, 'Use of Your Lot', 'Can I run a business from home?', 'A “home office” is permitted as long as no non-resident employees work on the property and no customers, employees, subcontractors, or other third parties park on the property. Any other business use requires prior written Board approval.', 'Declaration, Art. IV(G)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (36, 'Use of Your Lot', 'Can I lease or rent out my home?', 'Yes, but all leases must be in writing and are subject to the Declaration and all governing documents. No hotel-style or transient uses are allowed — this includes room service, maid service, furnishing of laundry or linen, or similar services, as well as leases to roomers or boarders.', 'Declaration, Art. IV(I)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (37, 'Use of Your Lot', 'Can I put up signs on my property?', 'Only certain signs are permitted: (1) one temporary “For Sale” sign up to 6 square feet; (2) marketing signs installed by owners or the Association while marketing lots and residences for sale; (3) street and identification signs installed by the Association or a governmental body; and (4) up to three temporary political signs (max 6 sq. ft. each) for a reasonable period before, and not more than 3 days after, a public governmental election in which lot owners are permitted to vote — only one sign per candidate or issue per lot, expressing only simple support or opposition. Political signs with other content may be removed by the Association. No signs may be placed on Association-owned Common Areas without Board approval.', 'Declaration, Art. IV(D)', 6);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (38, 'Use of Your Lot', 'What about trash and storage?', 'No open storage of any kind is permitted. Trash must be in covered, sanitary containers screened from view and stored inside a permitted structure or to the side or rear of the home. No burning of trash is allowed. Storage buildings (sheds, barns, etc.) must be approved by the Architectural Review Committee and must match the general décor of the residence.', 'Declaration, Art. IV(H), (K)', 7);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (39, 'Use of Your Lot', 'Are satellite dishes and antennas allowed?', 'Standard TV antennas and over-the-air reception devices (including satellite dishes) of 24 inches (2 feet) in diameter or less are permitted. Installation must comply with ARC or Board rules regarding location, screening, and reasonable color blending, provided those rules do not unreasonably increase the cost of installing, maintaining, or using the device, or unreasonably delay the owner’s right to receive acceptable over-the-air signals.', 'Declaration, Art. IV(L)', 8);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (40, 'Use of Your Lot', 'Are above-ground propane or fuel tanks allowed?', 'The Declaration provides that no tanks for propane gas or fuel oil shall be permitted above ground (Art. IV(N)). However, the Declaration also requires compliance with all applicable governmental regulations and provides that where governmental requirements conflict with the Declaration, the governmental requirements prevail automatically (Art. IV(R)). In areas where flood risk, fire code (including Ohio’s adoption of NFPA 58), or other regulatory requirements make underground tank installation impracticable or prohibited, owners should consult with the Board and the Architectural Review Committee about obtaining a variance (Art. V(C)) and should document any regulatory barriers. The ARC has authority to grant reasonable variances to avoid unnecessary hardship, provided the result is not prohibited by law and is in the best interest of the Subdivision.', 'Declaration, Art. IV(N), Art. IV(R), Art. V(C)', 9);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (41, 'Use of Your Lot', 'Must utility lines be underground?', 'Yes, all utility lines on the property must be underground, subject to requirements of relevant governmental authorities and utility companies.', 'Declaration, Art. IV(M)', 10);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (42, 'Pets & Animals', 'Can I have pets?', 'Yes, domestic pets are allowed but must be properly restrained and not permitted to roam free or loose on the property other than on the lot of the pet’s owner. No animal may be kept if its size, type, or characteristics constitute a threat to the safety and security of other property owners, their families, or guests. You are required to regularly remove pet waste from your lot. No animal may be kept, bred, boarded, or raised for breeding or other commercial purposes. The Board has the right to adopt additional rules regarding the number, size, and types of animals and may take appropriate action if any animal creates a detrimental effect on residents.', 'Declaration, Art. IV(E)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (43, 'Pets & Animals', 'Are dog houses, dog runs, or animal cages allowed?', 'Outdoor dog houses, animal cages, dog runs, and similar objects (whether or not affixed to the ground) are prohibited without the express prior review and approval of the Architectural Review Committee, which may be withheld in the ARC’s sole and unfettered discretion.', 'Declaration, Art. IV(E)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (44, 'Pets & Animals', 'Can I keep horses?', 'Stables are permitted only on lots exceeding 3 acres in size. No livestock other than horses may be stabled on any lot. A paddock must be built providing at least one-half acre of space per horse, and the fencing design must be approved by the Architectural Review Committee before construction.
<em>Note: The Declaration references six rental stalls formerly available at 541 Brindle Road. This service is no longer offered.</em>', 'Declaration, Art. IV(E)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (45, 'Pets & Animals', 'Is hunting or shooting allowed?', 'No. No hunting or discharge of firearms is permitted anywhere on the property or any lot.', 'Declaration, Art. IV(E)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (46, 'Vehicles & Parking', 'Can I park a commercial vehicle, RV, boat, or trailer on the street?', 'No. Commercial vehicles, snowmobiles, watercraft, trailers, campers, buses, and mobile homes may not be parked or stored on a subdivision street.', 'Declaration, Art. IV(J)(2)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (47, 'Vehicles & Parking', 'Can I store a commercial vehicle, RV, boat, or trailer on my lot?', 'Only if entirely contained and shielded from view within a permitted, enclosed structure.', 'Declaration, Art. IV(J)(1)–(2)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (48, 'Vehicles & Parking', 'What counts as a "commercial vehicle"?', 'Any vehicle designed and used exclusively or primarily for anything other than personal transportation of 10 or fewer persons. Vehicles larger than 10-passenger vans are conclusively presumed commercial. Passenger cars, passenger vans (full-sized or mini), pickups, SUVs, and motorcycles are presumed to be for personal transportation. A dual-use vehicle is not considered commercial merely because it has advertising painted or affixed to it. The Board has authority to grant exceptions for certain vehicles in accordance with Scioto Township parking setback regulations.', 'Declaration, Art. IV(J)(2)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (49, 'Vehicles & Parking', 'What if my car isn''t running — can I keep it on my lot?', 'An automobile or motorized vehicle that is not functionally or legally operable on public highways may not be kept, stored, operated, or maintained on or in front of any lot for more than 7 days, unless entirely contained and shielded from view within a permitted structure. After that period, it is considered a nuisance and the Board has authority to have it removed at the owner’s expense.', 'Declaration, Art. IV(J)(2)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (50, 'Vehicles & Parking', 'Can the Board make additional parking rules?', 'Yes. The Board is entitled to create and enforce reasonable rules concerning the parking of any vehicle on the property. The Board may levy Individual Lot Assessments as penalties for violations and is authorized to have any vehicle violating such rules removed — including vehicles on lots, unless located in permitted, enclosed structures shielded from view.', 'Declaration, Art. IV(J)(1)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (51, 'Architectural Review & Improvements', 'Do I need approval before building anything or making exterior changes?', 'Yes. No improvement may be placed, erected, or installed — and no construction (including staking, clearing, excavation, grading, and other site work), planting, or removal of plants, trees, or shrubs may occur — without first submitting a complete set of building plans to the Architectural Review Committee (ARC) and obtaining written approval. This also applies to altering exterior surfaces, changing paint colors or roofing materials, modifying fencing, and installing any recreational device.', 'Declaration, Art. V(A), (B)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (52, 'Architectural Review & Improvements', 'Who is on the Architectural Review Committee?', 'Currently: Lois Blumenstiel, Lisa Falvo, and James B. Blumenstiel. The ARC acts by decision of two or more of its three members. The Declarant has the right to appoint all ARC members as long as the Declarant owns one or more lots. Once the Declarant no longer owns any lots, the owners elect ARC members by majority vote of all owners.', 'Declaration, Art. V(A)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (53, 'Architectural Review & Improvements', 'How long does the ARC have to respond to my plans?', '30 days from submission. The ARC must approve, reject, or modify plans in a written statement sent to the owner within that period. If the ARC fails to act within 30 days, approval is deemed given and no further permission is needed to proceed with the submitted plans.', 'Declaration, Art. V(A)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (54, 'Architectural Review & Improvements', 'Can the ARC charge a fee for reviewing my plans?', 'Yes. The ARC may charge a nominal fee in connection with processing applications.', 'Declaration, Art. V(B)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (55, 'Architectural Review & Improvements', 'Can the ARC unreasonably deny my plans?', 'The ARC shall not unreasonably withhold approval of any plans that conform in every way to the Declaration and to the general character of improvements developed on neighboring lots.', 'Declaration, Art. V(A)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (56, 'Architectural Review & Improvements', 'Can the ARC grant variances?', 'Yes. To avoid unnecessary hardship or overcome practical difficulties, the ARC has authority to grant reasonable variances from the use restrictions in Article IV, the architectural standards in Article V, and any standards it has established — provided the activity is not prohibited by law and the variance is in the best interest of the Subdivision and within the spirit of the ARC’s standards. A variance granted to one owner does not waive any provision as applied to any other owner or property.', 'Declaration, Art. V(C)', 6);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (57, 'Architectural Review & Improvements', 'Can I remodel the inside of my home without approval?', 'Yes. Nothing in the Declaration limits your right to remodel or decorate the interior of your residence.', 'Declaration, Art. V(B)', 7);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (58, 'Fencing, Pools & Outdoor Features', 'What types of fences are allowed?', 'All fencing requires written ARC approval before installation. The ARC has authority to establish fencing standards, including the power to prohibit fencing entirely or to require or prohibit certain types in certain areas. General standards the ARC considers include: (1) acceptable materials are wood, wrought iron, stone, or brick — certain vinyl/plastic styles may be approved, but chain link and other metal or wire fencing is prohibited (dark-painted wire or plastic mesh attached to the inside of an approved fence is permitted); (2) maximum height of 48 inches above finished grade, except where a governmental agency requires taller for safety (e.g., pool enclosure); (3) fences may not be closer to any street than the platted building line, except ornamental railings/walls/fences not exceeding 3 feet near entrance platforms or steps; (4) fences must be parallel to property lines where possible and placed either at the property line (to allow adjacent owners to connect) or set back at least 3 feet from it — fences shall not “jog” around utility junction boxes unless the boxes physically straddle the property line.', 'Declaration, Art. IV(P)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (59, 'Fencing, Pools & Outdoor Features', 'Are above-ground swimming pools allowed?', 'No. Any pool extending 12 inches or more above finished grade and having either (1) a water surface area over 36 square feet, or (2) a filtration system of any description, is prohibited. Hot tubs and saunas are not prohibited by this section.', 'Declaration, Art. IV(Q)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (60, 'Fencing, Pools & Outdoor Features', 'Are lamp posts or yard lights regulated?', 'Yes. All yard lights and lamp posts must conform to standards set by the Architectural Review Committee.', 'Declaration, Art. IV(O)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (61, 'Common Areas', 'What are the Common Areas?', 'All real and personal property now or hereafter acquired by, or benefited by easement to, the Association for the common use and enjoyment of the owners, or for the operation of the Association. This can include open spaces, reserve areas, entranceways, community border features, detention areas, private drives, and other property designated by the Board. It also includes property the Association doesn’t own but is responsible for maintaining under the Declaration, zoning regulations, plats, or other agreements. The specific initial parcels are described in Exhibit C.', 'Declaration, Art. II(H)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (62, 'Common Areas', 'Can I use the pond?', 'Yes. Fishing, swimming, boating, and skating on any of the ponds are permitted for residents and their guests. Any resident may bring a canoe, kayak, raft, or similar floating device to use on the large pond. However, only the Association’s paddleboat may be left at the large pond overnight.', 'Declaration, Art. IV(B)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (63, 'Common Areas', 'Can anything be built on the Common Areas?', 'No improvements other than driveways, walkways, and sidewalks may be erected, placed, or permitted to remain on the Common Areas. All uses must benefit or promote the health, safety, welfare, convenience, comfort, recreation, and enjoyment of owners and occupants, and must comply with the Declaration, state law, the Rules, and other governing documents.', 'Declaration, Art. IV(B)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (64, 'Common Areas', 'Who maintains the Common Areas?', 'The Association is responsible for exclusive management, control, and maintenance of the Common Areas, including repair and replacement of all landscaping, structures, improvements, and personal property on them. The Board may also choose to maintain property the Association doesn’t own if it determines such maintenance benefits the Subdivision.', 'Declaration, Art. X(A); Art. VIII(A)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (65, 'Common Areas', 'Can the Association grant easements over Common Areas?', 'Yes. The Association has the right to grant easements to third parties over, across, under, or through Common Areas it owns — including for utility construction, conservation, and other purposes. However, the Association may not convey an easement over a lot without the prior written consent of that lot’s owner (which consent shall not be unreasonably delayed or withheld).', 'Declaration, Art. VIII(A); Art. VI(C)', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (66, 'Lot Maintenance & Association Entry', 'What maintenance am I responsible for?', 'Each owner must repair, replace, and maintain their lot and all improvements in good order and safe, sanitary condition at their own expense — except to the extent maintenance is expressly assumed by the Association or a governmental authority. This includes anything that, if omitted, would adversely affect the safety and usefulness of the common areas. You must also maintain portions of your lot adjacent to common areas per the Rules and Declaration. Pet waste removal is specifically included as part of proper lot maintenance.', 'Declaration, Art. X(B); Art. IV(E)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (67, 'Lot Maintenance & Association Entry', 'Can the Association enter my lot?', 'Yes. Authorized agents, officers, contractors, and employees of the Association have a right of entry for performing the Association’s rights or obligations under the governing documents. The Association may enter to remove or correct violations, or to maintain, repair, and replace common areas. Entry is permitted only during reasonable hours and after 72 hours’ advance notice to the owner, except in emergencies. If you fail to maintain your lot and the Board determines maintenance is necessary (for public safety, reasonable use of common areas, to prevent damage, or to comply with the Rules/Declaration), the Board may authorize employees or agents to enter and complete the work, then levy an Individual Lot Assessment for all reasonable expenses.', 'Declaration, Art. VI(B); Art. X(C)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (68, 'Lot Maintenance & Association Entry', 'What if I damage Common Areas?', 'The Board may levy an Individual Lot Assessment against you for the cost of repairing or replacing the damaged property. The damage may have been caused by you, your family members, guests, or invitees. The Association is entitled to enter your lot to repair or maintain common areas adjacent to it.', 'Declaration, Art. X(D)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (69, 'Insurance', 'What insurance does the Association carry?', 'The Association is required to maintain: (1) fire and extended coverage (special form) on all buildings, structures, fixtures, equipment, and common personal property constituting part of the Common Areas; (2) commercial general liability of at least $1,000,000 per occurrence and $2,000,000 aggregate, covering all Common Areas including all ponds accessible to owners, with a “severability of interest” endorsement; and (3) directors’ and officers’ liability of at least $1,000,000 per claim and in the aggregate, to the extent reasonably available. The Board may also obtain fidelity bond coverage, workers’ compensation, and other insurance it deems necessary.', 'Declaration, Art. VIII(E)(1)–(4)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (70, 'Insurance', 'Does the Association''s insurance cover my home?', 'No. The Association’s insurance covers Common Area property and Association liability only. Each owner is responsible for obtaining their own homeowner’s insurance for their lot and dwelling.', 'Declaration, Art. VIII(E)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (71, 'Insurance', 'What happens if Common Areas are damaged or destroyed?', 'The Association must promptly repair or replace, to the extent insurance proceeds are available. Each member is deemed to have appointed the Association as their attorney-in-fact for this purpose. If insurance proceeds are insufficient, the Board may levy a Special Assessment to cover the shortfall.', 'Declaration, Art. VIII(E)(5)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (72, 'Enforcement, Fines & Disputes', 'What can the Board do if I violate the governing documents?', 'The Board may: (1) impose reasonable monetary fines or charges as Individual Lot Assessments, as permitted by law; (2) suspend your right to vote as a member; (3) suspend your right to use common areas owned by the Association; and (4) seek relief in any court, including injunctions and damages. If the Board incurs attorney fees or litigation expenses in enforcement against you (or your tenant, guest, or invitee), the full amount is due from you as an Individual Lot Assessment against your lot.', 'Declaration, Art. VIII(B)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (73, 'Enforcement, Fines & Disputes', 'Do I get notice before being fined?', 'Yes (except for fines related to utility charges, interest, late charges, returned check charges, court costs, arbitration costs, or attorney fees, which do not require prior notice). For other Individual Lot Assessments, the Board must give you written notice that includes: (1) a description of the property damaged or the violation; (2) the proposed fine amount; (3) your right to request a hearing before the Board within 10 days of receiving the notice; and (4) for rule violations, a reasonable cure date. Notice may be delivered personally, to an occupant of your lot, by certified mail with return receipt, or by regular mail. If you request and receive a hearing and the Board still imposes the fine, they must deliver written notice of their decision within 30 days of the hearing.', 'Declaration, Art. IX(F)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (74, 'Enforcement, Fines & Disputes', 'Can I challenge a lien the Association has placed on my lot?', 'Yes. You may bring an action in the Delaware County Court of Common Pleas for discharge of the lien and/or a declaratory judgment that the assessment was unlawful. However, filing the lawsuit does not entitle you to offset or withhold payment. If the court determines all or part of the assessment was improperly charged, it may order discharge of the lien and/or a refund.', 'Declaration, Art. IX(G)(7)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (75, 'Enforcement, Fines & Disputes', 'Who can enforce the Declaration?', 'Any owner, the Association, the Board, the Architectural Review Committee, and their respective heirs, successors, and assigns. Enforcement may include proceedings at law or in equity to restrain or enjoin violations, specific performance to require removal of nonconforming improvements, and recovery of damages, enforcement costs, and reasonable attorney fees. By accepting a deed, each owner is deemed to waive the defenses of laches and statute of limitations. Failure to enforce any provision in any instance does not constitute a waiver of the right to enforce it in other instances.', 'Declaration, Art. XI(B)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (76, 'Amendments, Duration & Miscellaneous', 'How long does the Declaration last?', '40 years from the date it was recorded, then automatically renews forever in successive 10-year periods. It can only be terminated with written consent of members holding at least 80% of total voting power and, if the Declarant still owns any lots, the Declarant’s written consent as well. Termination must be recorded with the Delaware County Recorder.', 'Declaration, Art. XI(A)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (77, 'Amendments, Duration & Miscellaneous', 'How can the Declaration be amended?', 'By approval of owners holding at least 75% of total voting power, either in writing or at a meeting called for that purpose. Important limitations: (1) the Declarant’s consent is required for any amendment affecting the Declarant’s rights; (2) unanimous consent of all owners is required for amendments changing voting power, the method of allocating common expenses, or the fundamental purpose of the Association, or to terminate the Declaration; (3) the Declaration may never be amended to eliminate the Association’s responsibility to repair and maintain common areas or to remove the requirement that owners be members and pay assessments; (4) no amendment may remove, revoke, or modify any Declarant right without the Declarant’s written consent. Amendments must be executed by the president and secretary of the Association with their certification of proper adoption and are effective upon filing with the Delaware County Recorder.', 'Declaration, Art. XI(C)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (78, 'Amendments, Duration & Miscellaneous', 'How can the Bylaws be amended?', 'By the affirmative vote of members holding at least 75% of total voting power, at a meeting held for that purpose or in a vote conducted by mail. Any amendment terminating and dissolving the Association requires unanimous consent of all owners.', 'Bylaws, Art. VIII, §8.01', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (79, 'Amendments, Duration & Miscellaneous', 'Can I inspect the Association''s books and records?', 'Yes. Upon reasonable request, the Association must make its books, records, and financial statements reasonably available for your inspection. Exceptions apply for items deemed privileged, protected, or confidential under applicable law, including: (1) personnel matters; (2) communications with legal counsel or attorney work product related to proposed or pending litigation; (3) contracts or transactions under negotiation or subject to confidentiality; (4) enforcement matters against specific owners; and (5) information prohibited from disclosure by state or federal law. The Association may charge a reasonable fee for handling and copying.', 'Declaration, Art. VIII(G)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (80, 'Amendments, Duration & Miscellaneous', 'Are directors and officers protected from personal liability?', 'Yes. The Association indemnifies directors and officers against expenses (including attorney fees), judgments, fines, and settlements from lawsuits arising from their service, provided they acted in good faith and in a manner they reasonably believed to be in or not opposed to the Association’s best interests. Individuals claiming indemnification are presumed to have met this standard; the burden is on challengers to prove otherwise. The Association also maintains D&O insurance of at least $1,000,000. Indemnification does not apply if a director is adjudged liable for reckless disregard for the Association’s best interests or misconduct (other than negligence).', 'Bylaws, Art. VI, §6.01–6.02', 5);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (81, 'Amendments, Duration & Miscellaneous', 'What is the role of the "Declarant"?', 'The Declarant is James B. Blumenstiel (and any manager, member, officer, successor, or assignee to which Declarant specifically assigns rights in writing). As long as the Declarant owns one or more lots, the Declarant retains certain rights including: appointing all ARC members; completing development, construction, promotion, marketing, and sales; maintaining model homes, offices, construction yards, and similar facilities on Declarant-owned property; posting development signs; re-platting Declarant-owned property; and veto power over amendments affecting Declarant rights. Improvements constructed by the Declarant or Declarant-approved builders are deemed to comply with the Declaration and do not require ARC approval.', 'Declaration, Art. II(J); Art. V(A), (D); Art. XI(C)–(E)', 6);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (82, 'Amendments, Duration & Miscellaneous', 'What about condemnation of Common Areas?', 'The Association represents all owners in any condemnation proceedings or negotiations for acquisition of Common Areas. Awards or proceeds are payable to the Association to be held in trust for the owners.', 'Declaration, Art. VIII(F)', 7);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (83, 'Amendments, Duration & Miscellaneous', 'Can the Association hire a property manager?', 'Yes. The Board may retain a Manager and delegate administrative duties. The Manager’s compensation is a Common Expense. Management agreements may not exceed 3 years and must allow termination by either party, without cause and without penalty, upon no more than 90 days’ written notice. Part of the Manager’s compensation may include miscellaneous fees payable in the event of transfers or other transactions involving the lots.', 'Declaration, Art. VIII(D)', 8);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (84, 'Amendments, Duration & Miscellaneous', 'How are notices delivered to owners?', 'In writing, by personal delivery at the lot (if a residence is constructed), or by depositing the notice in U.S. Mail, first class, postage prepaid, to the owner’s address on file with the Association or as otherwise designated in writing by the owner.', 'Declaration, Art. XI(I)', 9);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (85, 'Amendments, Duration & Miscellaneous', 'Do first mortgage holders have any special rights?', 'Yes. A holder or insurer of a first mortgage, upon written request to the Association (which must state the name, address, and lot description), is entitled to timely written notice of: (1) any proposed amendment of the Declaration; (2) any proposed termination of the Association; and (3) any uncured default lasting 60 or more days that gives rise to a cause of action by the Association against the lot owner. Mortgage holders may also inspect the Association’s books and records at their own expense during normal business hours.', 'Declaration, Art. XI(F)', 10);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (86, 'Easements & Access', 'What easement rights do I have over Common Areas?', 'Every owner has a right and easement of enjoyment in, over, and upon the Common Areas, plus a right of access to and from their lot. These rights are appurtenant to and pass with title to your lot. You may delegate these rights to family members, occupants, guests, and invitees. All easement rights are subject to the Declaration and the Rules, and no person may use these easements to engage in activities not otherwise permitted.', 'Declaration, Art. VI(A)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (87, 'Easements & Access', 'What are "No-Build Zones"?', 'Areas designated on recorded plats, re-plats, prior deed restrictions, or Exhibit D (if attached) where no owner may construct or locate any improvements, including fencing. Landscaping may be placed in No-Build Zones only with prior ARC approval. In vegetated No-Build Zones, owners may perform maintenance necessary for safety (removing noxious or poisonous plants, or dead trees that could harm persons or improvements). Grassed No-Build Zones must be mowed, trimmed, and watered by the person responsible for that area.', 'Declaration, Art. VI(G)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (88, 'Easements & Access', 'Can the Association grant utility easements over my lot?', 'The Association may grant easements over Common Areas it owns for utilities and other purposes, but may not convey an easement over your lot without your prior written consent (which you may not unreasonably delay or withhold). However, the Association does have the absolute right to enter lots within areas designated as drainage courses on the recorded plat, areas encumbered by general utility or storm drainage easements, and areas determined by sound engineering practice to be necessary for proper drainage — to install, modify, or work on storm water drainage facilities. If such work damages your lot or improvements, the Association must restore them at its own cost.', 'Declaration, Art. VI(C)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (89, 'Easements & Access', 'Who else has easement rights to enter the property?', 'A non-exclusive easement is granted to police, firefighters, ambulance operators, mail carriers, delivery persons, garbage removal personnel, similar service providers, local governmental authorities, and the Association (but not the general public) to enter Common Areas to perform their duties. A separate easement is granted to the Association for maintenance responsibilities on the property.', 'Declaration, Art. VI(D), (E)', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (90, 'Nuisances & Hazardous Activities', 'What constitutes a nuisance?', 'No noxious or offensive trade is permitted on the property. No use may be made or condition allowed to exist on any lot that unreasonably disturbs or interferes with the safety and quiet occupancy of any person residing on any other lot.', 'Declaration, Art. IV(F)', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (91, 'Nuisances & Hazardous Activities', 'Are hazardous materials or activities prohibited?', 'Nothing may be done or kept on any lot or common area that is unlawful or hazardous, that might reasonably increase casualty or public liability insurance costs for the Common Areas, or that might unreasonably disturb the quiet occupancy of other residents. This does not prohibit the Association from performing construction activities consistent with residential construction practices.', 'Declaration, Art. IV(C)', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (92, 'Nuisances & Hazardous Activities', 'What about compliance with zoning?', 'The Declaration requires compliance with all governmental zoning and development plan requirements for as long as they are effective. If the underlying governmental obligation is changed, modified, or lapses, the Declaration is automatically deemed modified accordingly without any action needed by the Association or members.', 'Declaration, Art. IV(R)', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (93, 'Officers', 'What officers does the Association have?', 'The officers are a President, a Secretary, a Treasurer, and such other officers as the Board determines. All officers must be elected by the Board from among the Board’s own members. Officers serve at the pleasure of the Board, and two or more offices may be held by the same person. Like directors, officers receive no compensation but may be reimbursed for actual expenses.', 'Bylaws, Art. V, §5.01', 1);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (94, 'Officers', 'What does the President do?', 'The President presides at all meetings of Members and the Board, exercises general supervision over the Association’s affairs, and performs all duties incident to the office or required by the Board.', 'Bylaws, Art. V, §5.02', 2);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (95, 'Officers', 'What does the Secretary do?', 'The Secretary keeps (or causes to be kept) accurate records of acts and proceedings of Members and the Board, including names and addresses of Members. Upon leaving office, the Secretary must deliver all Association books, records, and documents to their successor or the President.', 'Bylaws, Art. V, §5.03', 3);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (96, 'Officers', 'What does the Treasurer do?', 'The Treasurer receives and safely keeps all money, securities, and other intangible property; disburses funds under Board direction; keeps correct and complete books of account showing receipts, expenditures, and the allocation and collection of assessments; presents financial abstracts at annual meetings or upon request; and may be required to give bond. Upon leaving office, the Treasurer must deliver all Association money and property to their successor or the President.', 'Bylaws, Art. V, §5.04', 4);
INSERT OR IGNORE INTO faqs (id, category, question, answer, reference, sort_order) VALUES (97, 'Enforcement, Fines & Disputes', 'If someone sues the Association over the covenants, who pays the legal fees?', 'The governing documents are clear: the Association has both the authority and the obligation to enforce the Declaration, and the costs of doing so — including defending against challenges — are borne by the community and, in many cases, recoverable from the challenging party.<br><br>When the Association incurs attorney fees or litigation expenses in enforcing the Declaration against an owner (or their tenant, guest, or invitee), the <strong>full amount</strong> is due from that owner as an Individual Lot Assessment against their lot (Art. VIII(B)). This includes defensive enforcement — if an owner sues to invalidate or circumvent a covenant and the Association must defend its governing documents, the legal costs become that owner''s Individual Lot Assessment.<br><br>The Board is also expressly authorized to hire attorneys and other professionals as a Common Expense (Bylaws §4.10), and may levy Special Assessments to cover unanticipated costs like litigation defense (Art. IX(C)). Directors and officers who act in good faith are indemnified against legal expenses arising from their service, including attorney fees, judgments, and settlements (Bylaws §6.01–6.02), backed by at least $1,000,000 in D&amp;O insurance (Art. VIII(E)(3)).<br><br>In short: if a member forces the Association into court to defend the covenants, that member may end up paying both sides'' legal bills — their own, plus the Association''s costs assessed back to their lot. The Association is well-positioned to defend its governing documents, and the financial risk falls squarely on the party that initiates the challenge.', 'Declaration, Art. VIII(B); Art. IX(B)(3), (C), (F); Bylaws, Art. IV, §4.10; Art. VI, §6.01–6.02', 5);
